import { Link, useNavigate } from "react-router-dom";
import { Search, ShoppingCart, LayoutDashboard, Store, Star, Scale } from "lucide-react";
import { useState, useEffect, useRef } from "react";
import useStore from "../store/useStore";
import api from "../api/axios";
import ThemeToggle from "./ThemeToggle";
import { motion, AnimatePresence } from "framer-motion";

export default function Navbar() {
  const [searchQuery, setSearchQuery] = useState("");
  const [searchResults, setSearchResults] = useState([]);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);

  const { activeUser, logoutActiveUser, cart } = useStore();
  const navigate = useNavigate();
  const searchRef = useRef(null);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 10);
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (searchRef.current && !searchRef.current.contains(event.target)) {
        setIsSearchOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  useEffect(() => {
    if (searchQuery.length < 2) {
      setSearchResults([]);
      return;
    }
    const debounce = setTimeout(async () => {
      try {
        const res = await api.get(`/products?keyword=${searchQuery}`);
        setSearchResults(res.data.products || res.data || []);
      } catch (err) {
        console.error("Search failed", err);
      }
    }, 300);
    return () => clearTimeout(debounce);
  }, [searchQuery]);

  return (
    <motion.nav 
      initial={{ y: -100 }}
      animate={{ y: 0 }}
      transition={{ type: "spring", stiffness: 100, damping: 20 }}
      className={`sticky top-0 z-50 w-full transition-all duration-300 ${
        isScrolled 
          ? "bg-white/70 dark:bg-[#0A101D]/70 backdrop-blur-xl border-b border-white/20 dark:border-slate-800/50 shadow-sm" 
          : "bg-white dark:bg-[#0A101D] border-b border-slate-200 dark:border-slate-800"
      }`}
    >
      <div className="mx-auto flex h-20 max-w-7xl items-center justify-between px-4 sm:px-6 lg:px-8">

        {/* Left Side - Brand & Navigation */}
        <div className="flex items-center gap-8">

          <Link to="/" className="flex items-center gap-3 group">
            <div className="flex h-12 w-12 items-center justify-center rounded-xl bg-gradient-to-br from-primary to-primary-dark shadow-lg shadow-primary/30 transform group-hover:scale-105 transition-all">
              <div className="w-5 h-5 border-2 border-white rounded-full"></div>
            </div>
            <div className="flex flex-col">
              <span className="text-2xl font-serif font-black dark:text-white text-slate-900 leading-none tracking-tight">ReviewLens</span>
              <span className="text-[10px] uppercase text-primary font-bold tracking-widest mt-1">Electronics</span>
            </div>
          </Link>

          <div className="hidden lg:flex items-center gap-8 ml-8 text-sm font-semibold text-slate-500 dark:text-slate-400">
            <Link to="/" className="flex items-center gap-2 hover:text-primary transition-colors">
              <Store className="w-4 h-4" /> Store
            </Link>
            <Link to="/dashboard" className="flex items-center gap-2 hover:text-primary transition-colors">
              <LayoutDashboard className="w-4 h-4" /> Dashboard
            </Link>
            <Link to="/compare" className="flex items-center gap-2 hover:text-accent transition-colors">
              <Scale className="w-4 h-4" /> Compare
            </Link>
          </div>
        </div>

        {/* Center - Search Bar */}
        <div className="hidden md:flex flex-1 max-w-xl mx-8 relative" ref={searchRef}>
            <div className="relative w-full group">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400 group-focus-within:text-primary transition-colors" />
              <input
                type="text"
                value={searchQuery}
                onChange={(e) => {
                  setSearchQuery(e.target.value);
                  setIsSearchOpen(true);
                }}
                onFocus={() => setIsSearchOpen(true)}
                placeholder="Search for laptops, phones, headphones..."
                className="w-full bg-slate-100 dark:bg-[#111A2E] border border-transparent dark:border-slate-800 text-slate-900 dark:text-white text-sm rounded-full py-3 pl-12 pr-4 focus:outline-none focus:bg-white dark:focus:bg-[#1C2333] focus:border-primary/50 focus:ring-4 focus:ring-primary/10 transition-all shadow-inner"
              />
            </div>

            <AnimatePresence>
              {isSearchOpen && searchResults.length > 0 && (
                <motion.div 
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: 10 }}
                  className="absolute left-0 right-0 top-full mt-3 rounded-2xl border border-slate-200 dark:border-slate-800 bg-white dark:bg-[#111A2E] shadow-2xl overflow-hidden z-50"
                >
                  {searchResults.slice(0, 5).map(item => (
                    <Link 
                      key={item._id} 
                      to={`/product/${item._id}`}
                      onClick={() => { setIsSearchOpen(false); setSearchQuery(""); }}
                      className="flex items-center gap-4 border-b border-slate-100 dark:border-slate-800/50 p-4 hover:bg-slate-50 dark:hover:bg-[#1C2333] transition-colors"
                    >
                      <div className="bg-slate-50 dark:bg-[#0A101D] p-2 rounded-lg">
                        <img src={item.image || item.images?.[0] || 'https://via.placeholder.com/40'} alt={item.name} className="w-12 h-12 object-contain" />
                      </div>
                      <div className="flex flex-col flex-1">
                        <span className="text-sm font-semibold text-slate-900 dark:text-white line-clamp-1">{item.name || item.title}</span>
                        <div className="flex items-center gap-2 mt-1">
                           <span className="text-sm font-bold text-accent">₹{item.price?.toLocaleString("en-IN")}</span>
                           {item.rating && (
                             <span className="flex items-center text-xs text-slate-500"><Star className="w-3 h-3 text-yellow-400 fill-yellow-400 mr-1"/> {item.rating}</span>
                           )}
                        </div>
                      </div>
                    </Link>
                  ))}
                </motion.div>
              )}
            </AnimatePresence>
        </div>

        {/* Right Side - Actions & Auth */}
        <div className="flex items-center gap-4 sm:gap-6">
          <ThemeToggle />

          <Link to="/cart" className="relative group p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors">
            <ShoppingCart className="w-6 h-6 text-slate-600 dark:text-slate-300 group-hover:text-primary transition-colors" />
            {cart?.length > 0 && (
              <motion.span 
                initial={{ scale: 0 }}
                animate={{ scale: 1 }}
                className="absolute top-0 right-0 flex h-5 w-5 items-center justify-center rounded-full bg-accent text-[10px] font-bold text-white shadow-lg border-2 border-white dark:border-[#0A101D]"
              >
                {cart.length}
              </motion.span>
            )}
          </Link>

          {activeUser ? (
             <div className="relative group ml-2">
                <button className="flex items-center justify-center w-10 h-10 rounded-full bg-gradient-to-br from-primary-light to-primary text-white font-bold shadow-md hover:shadow-lg transform hover:scale-105 transition-all border-2 border-transparent hover:border-primary-light">
                  {activeUser.name?.charAt(0).toUpperCase() || "U"}
                </button>

                {/* Dropdown Menu */}
                <div className="absolute right-0 top-full mt-3 w-56 bg-white dark:bg-[#111A2E] border border-slate-200 dark:border-slate-800 rounded-2xl shadow-xl overflow-hidden opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 z-50 transform origin-top-right group-hover:scale-100 scale-95">
                  <div className="p-4 bg-slate-50 dark:bg-[#0A101D]/50 border-b border-slate-100 dark:border-slate-800">
                    <p className="text-slate-900 dark:text-white font-semibold truncate">{activeUser.name}</p>
                    <p className="text-xs text-slate-500 truncate mt-0.5">{activeUser.email}</p>
                  </div>
                  <div className="p-2 space-y-1">
                    {(activeUser.role === "Seller" || activeUser.role === "Admin" || true) && (
                      <button 
                        onClick={() => navigate("/add-product")} 
                        className="w-full text-left block px-3 py-2.5 text-sm text-primary font-medium hover:bg-primary/10 rounded-xl transition-colors"
                      >
                        + Add Product
                      </button>
                    )}
                    <Link to="/profile" className="block px-3 py-2.5 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl transition-colors">
                      My Profile
                    </Link>
                    <Link to="/settings" className="block px-3 py-2.5 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl transition-colors">
                      Settings
                    </Link>
                    <div className="my-1 border-t border-slate-100 dark:border-slate-800"></div>
                    <button 
                      onClick={() => { logoutActiveUser(); navigate('/'); }} 
                      className="w-full text-left px-3 py-2.5 text-sm text-red-500 font-medium hover:bg-red-50 dark:hover:bg-red-500/10 rounded-xl transition-colors"
                    >
                      Sign Out
                    </button>
                  </div>
                </div>
             </div>
          ) : (
            <div className="flex items-center gap-3 ml-2">
              <Link to="/login" className="hidden sm:block text-slate-600 dark:text-slate-300 hover:text-primary dark:hover:text-primary font-semibold text-sm transition-colors">
                Sign In
              </Link>
              <Link to="/register" className="bg-primary hover:bg-primary-dark text-white font-semibold text-sm px-5 py-2.5 rounded-xl shadow-md shadow-primary/20 hover:shadow-lg hover:-translate-y-0.5 transition-all">
                Register
              </Link>
            </div>
          )}
        </div>

      </div>
    </motion.nav>
  );
}

import { Link, useNavigate } from "react-router-dom";
import { Star, TrendingUp, Sparkles, Check, Heart, ShieldCheck, Zap, Plus, Award } from "lucide-react";
import useStore from "../store/useStore";
import toast from "react-hot-toast";
import { motion } from "framer-motion";

export default function ProductCard({ p, badgeType }) {
  const navigate = useNavigate();
  const { addToCart, addToCompare, compareList = [] } = useStore();

  if (!p) return null;

  const isTrending = badgeType === "trending";
  const isBest = badgeType === "best";

  const isCompared = compareList?.some(item => item._id === p._id);

  // 🎨 Sentiment styling
  let sentimentColor = "text-slate-500 dark:text-slate-400";
  let sentimentBg = "bg-slate-100 dark:bg-[#1C2333] border-slate-200 dark:border-slate-800";
  let sentimentIcon = <Zap className="w-3 h-3" />;

  if (p?.sentiment === "Positive") {
    sentimentColor = "text-emerald-600 dark:text-emerald-400";
    sentimentBg = "bg-emerald-50 dark:bg-emerald-500/10 border-emerald-200 dark:border-emerald-500/20";
    sentimentIcon = <ShieldCheck className="w-3 h-3" />;
  } else if (p?.sentiment === "Negative") {
    sentimentColor = "text-red-600 dark:text-red-400";
    sentimentBg = "bg-red-50 dark:bg-red-500/10 border-red-200 dark:border-red-500/20";
    sentimentIcon = <TrendingUp className="w-3 h-3 rotate-180" />;
  } else if (p?.sentiment === "Neutral") {
    sentimentColor = "text-amber-600 dark:text-amber-400";
    sentimentBg = "bg-amber-50 dark:bg-amber-500/10 border-amber-200 dark:border-amber-500/20";
    sentimentIcon = <TrendingUp className="w-3 h-3" />;
  }

  // 🛒 Add to Cart
  const handleAddToCart = (e) => {
    e.preventDefault(); // prevent triggering Link
    e.stopPropagation(); // prevent event bubbling to Link
    addToCart(p);
    toast.success("Added to cart");
  };

  // 💳 Buy Now → cart → navigate
  const handleBuyNow = (e) => {
    e.preventDefault();
    e.stopPropagation();
    addToCart(p);
    navigate("/cart");
  };

  const isCategoryMismatch = compareList?.length > 0 && !isCompared && compareList?.[0]?.category !== p?.category;

  // 🔁 Compare
  const handleCompare = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (isCategoryMismatch) {
      toast.error(`Please select products from the same category (${compareList[0].category})`);
      return;
    }

    if (isCompared) {
      navigate("/compare");
      return;
    }

    if (compareList?.length >= 3) {
      toast.error("Compare limit exceeded (Max 3)");
      return;
    }

    addToCompare(p);
    toast.success("Added to compare");
  };

  return (
    <Link to={`/product/${p._id}`} className="block h-full">
      <motion.div 
        initial={{ opacity: 0, y: 20 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true }}
        transition={{ duration: 0.4 }}
        className="group relative flex flex-col justify-between rounded-2xl bg-white dark:bg-[#111A2E] border border-slate-200 dark:border-slate-800 p-5 shadow-lg hover:shadow-2xl hover:shadow-primary/10 transition-all duration-300 h-full"
      >


      {/* Image Container */}
      <div className="relative mb-5 overflow-hidden rounded-xl bg-slate-50 dark:bg-[#0A101D] p-6 aspect-[4/3] flex items-center justify-center group-hover:bg-primary/5 dark:group-hover:bg-primary/10 transition-colors">
        <motion.img
          whileHover={{ scale: 1.08 }}
          transition={{ type: "spring", stiffness: 200, damping: 20 }}
          src={p?.images?.[0]?.url || p?.image || "https://via.placeholder.com/300"}
          alt={p?.name || "Product"}
          className="object-contain h-full w-full drop-shadow-md relative z-10"
        />

        {/* PRAS Badge (Top Left) */}
        {p?.sentimentScore && (
          <div className="absolute top-3 left-3 z-30 flex items-center gap-1 rounded-full bg-white/90 dark:bg-[#111A2E]/90 backdrop-blur-md px-2.5 py-1 text-xs font-bold border border-slate-200 dark:border-slate-700 shadow-sm">
            <Sparkles className={`w-3.5 h-3.5 ${sentimentColor}`} />
            <span className="text-slate-800 dark:text-white">{p.sentimentScore}</span>
          </div>
        )}

        {/* Dynamic Badges (Bottom Left) */}
        {isTrending && (
          <div className="absolute bottom-3 left-3 z-30 flex items-center gap-1 bg-indigo-500 text-white px-2.5 py-1 rounded-full text-[10px] font-bold shadow-md">
            <TrendingUp className="w-3 h-3" /> Trending
          </div>
        )}
        {isBest && (
          <div className="absolute bottom-3 left-3 z-30 flex items-center gap-1 bg-orange-500 text-white px-2.5 py-1 rounded-full text-[10px] font-bold shadow-md">
            <Award className="w-3 h-3" /> Best Product
          </div>
        )}

        {/* Compare Button (Top Right) */}
        <button 
          onClick={handleCompare}
          disabled={isCategoryMismatch && !isCompared}
          className={`absolute top-3 right-3 z-30 w-8 h-8 rounded-full flex items-center justify-center transition-all shadow-md backdrop-blur-md ${
            isCompared 
              ? 'bg-indigo-500 text-white border border-indigo-600' 
              : 'bg-white/80 dark:bg-[#111A2E]/80 text-slate-500 hover:text-indigo-500 hover:bg-white dark:hover:bg-[#111A2E] border border-slate-200 dark:border-slate-700'
          } ${isCategoryMismatch && !isCompared ? 'opacity-50 cursor-not-allowed' : ''}`}
        >
          {isCompared ? <Check className="w-4 h-4" /> : <Plus className="w-4 h-4" />}
        </button>
      </div>

      {/* Info Section */}
      <div className="flex-1 relative z-10">
        <div className="flex items-start justify-between gap-2 mb-1">
          <p className="text-xs font-bold uppercase tracking-wider text-primary">{p?.brand || "Brand"}</p>
          <div className={`flex items-center gap-1 px-2 py-0.5 text-[10px] font-bold rounded-full border ${sentimentBg} ${sentimentColor}`}>
            {sentimentIcon}
            {p?.sentiment || "Neutral"}
          </div>
        </div>

        <h2 className="font-bold text-[17px] leading-tight text-slate-900 dark:text-slate-100 line-clamp-2 mb-3 group-hover:text-primary transition-colors">
          {p?.name || "Unknown"}
        </h2>

        <div className="flex items-center gap-3">
          <div className="flex items-center gap-1 bg-yellow-100/50 dark:bg-yellow-500/10 px-2 py-1 rounded-md text-sm font-bold text-yellow-600 dark:text-yellow-400">
            <Star className="w-3.5 h-3.5 fill-current" />
            <span>{p?.ratings || p?.rating || "0.0"}</span>
          </div>
          <span className="text-xs text-slate-500 font-medium">({p?.reviews?.length || 0} reviews)</span>
        </div>
      </div>

      {/* Price & Actions */}
      <div className="mt-5 relative z-10">
        <div className="flex items-end gap-2 mb-4">
          <span className="text-2xl font-black text-slate-900 dark:text-white">
            ₹{(p?.price || 0).toLocaleString("en-IN")}
          </span>
          <span className="text-sm text-slate-500 line-through mb-1">
            ₹{Math.floor((p?.price || 0) * 1.2).toLocaleString("en-IN")}
          </span>
        </div>

        <div className="grid grid-cols-2 gap-3">
          <button
            onClick={handleAddToCart}
            className="w-full relative z-30 bg-slate-100 dark:bg-[#1C2333] hover:bg-slate-200 dark:hover:bg-slate-800 text-slate-900 dark:text-white py-2.5 rounded-xl font-semibold text-sm transition-colors border border-slate-200 dark:border-slate-700"
          >
            Add to Cart
          </button>

          <button
            onClick={handleBuyNow}
            className="w-full relative z-30 bg-accent hover:bg-accent-hover text-white py-2.5 rounded-xl font-semibold text-sm transition-all shadow-md shadow-accent/20 hover:shadow-lg hover:-translate-y-0.5"
          >
            Buy Now
          </button>
        </div>
      </div>
      </motion.div>
    </Link>
  );
}

import { Link, useLocation } from "react-router-dom";
import { LayoutDashboard, Scale, TrendingUp, User, Settings, Sparkles, MessageSquare } from "lucide-react";
import { motion } from "framer-motion";

export default function Sidebar() {
  const location = useLocation();

  const navItems = [
    { name: "Dashboard", path: "/dashboard", icon: LayoutDashboard },
    { name: "Compare", path: "/compare", icon: Scale },
    { name: "Reviews", path: "/reviews", icon: MessageSquare },
    { name: "Settings", path: "/settings", icon: Settings },
  ];

  return (
    <aside className="w-64 h-screen flex-shrink-0 bg-gradient-to-b from-indigo-500 to-purple-600 text-white flex flex-col transition-all duration-300 shadow-xl z-20">
      {/* Branding */}
      <div className="p-6">
        <Link to="/" className="flex flex-col">
          <span className="text-2xl font-black tracking-tight leading-none text-white">ReviewLens</span>
          <span className="text-xs font-semibold text-indigo-100 tracking-wider mt-1 opacity-90">Sentiment Analysis</span>
        </Link>
      </div>

      {/* Navigation */}
      <nav className="flex-1 px-4 py-6 space-y-2 overflow-y-auto">
        {navItems.map((item) => {
          const Icon = item.icon;
          const isActive = location.pathname === item.path || (item.path !== "/" && location.pathname.startsWith(item.path));

          return (
            <Link
              key={item.name}
              to={item.path}
              className={`flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all duration-200 ${
                isActive 
                  ? "bg-white/20 text-white shadow-inner" 
                  : "text-indigo-100 hover:bg-white/10 hover:text-white"
              }`}
            >
              <Icon className="w-5 h-5" />
              <span>{item.name}</span>
            </Link>
          );
        })}
      </nav>

      {/* Pro Tip Card */}
      <div className="p-4 mb-4">
        <motion.div 
          whileHover={{ scale: 1.02 }}
          className="bg-white/10 border border-white/20 rounded-2xl p-4 shadow-lg backdrop-blur-sm"
        >
          <div className="flex items-center gap-2 mb-2">
            <Sparkles className="w-4 h-4 text-yellow-300" />
            <span className="text-sm font-bold text-white">Pro Tip</span>
          </div>
          <p className="text-xs text-indigo-100 leading-relaxed">
            Compare products to find the best deals!
          </p>
        </motion.div>
      </div>
    </aside>
  );
}

